const body = ($input.first() && $input.first().json && $input.first().json.body) || {};
const s = body.submission || {};
const email = String(s.email || '').trim();
if (!email) throw new Error('email required');
let id = String(s.id || '').trim();
if (!id) { id = 'o_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,8); }
const now = new Date().toISOString();
const row = {
  id,
  slug: String(s.slug || '').trim(),
  first_name: String(s.first_name || '').trim(),
  last_name: String(s.last_name || '').trim(),
  email,
  phone: String(s.phone || '').trim(),
  ai_avatar: String(s.ai_avatar || '').trim(),
  answers: (s.answers && typeof s.answers === 'object') ? s.answers : {},
  status: 'submitted',
  source: String(s.source || 'syncview-onboarding'),
  created_at: String(s.created_at || now),
  updated_at: now
};
return [{ json: row }];

